131	                vec![key_timed("KEY_E", 200, 100)],
132	            ),
133	            macro_with_flags(
134	                "Clear Hellbomb Flag",
135	                "hellbomb gone",
136	                None,
137	                Some("hellbomb_armed"),
138	                vec![],
139	            ),
140	        ],
141	    };
142	
143	    Pack {
144	        name: "Helldivers 2".to_string(),
145	        author: Some("community".to_string()),
146	        categories: vec![stratagems, support_weapons, flags],
147	    }
148	}
