515	fn hd2_pack_full_lifecycle_export_import_activate_retrieve() {
516	    let export_dir = tempfile::tempdir().unwrap();
517	    let config_root = tempfile::tempdir().unwrap();
518	
519	    // 1. Build and export the HD2 pack
520	    let pack = hd2_pack();
