522	    let zip_path = export_dir.path().join("helldivers2.hdpack");
523	    pack.export(export_dir.path(), &zip_path).unwrap();
524	
525	    // 2. Import it (extracts to profiles/Helldivers 2/)
526	    std::env::set_var("XDG_CONFIG_HOME", config_root.path());
527	    let imported = Pack::import(&zip_path).expect("import must succeed");
528	    assert_eq!(imported.name, "Helldivers 2");
529	
530	    // 3. Set as active profile and retrieve it
531	    let manager = ProfileManager {
532	        active_profile: Some("Helldivers 2".to_string()),
533	    };
534	    let active = manager
535	        .get_active_pack()
536	        .expect("get_active_pack must succeed")
537	        .expect("active pack must be present");
538	    std::env::remove_var("XDG_CONFIG_HOME");
539	
540	    assert_eq!(active.name, "Helldivers 2");
541	    let flat = active.flatten();
542	    assert_eq!(flat.len(), 9);
