8	/// A macro pack (profile) consisting of categorized macros.
9	#[derive(Debug, Clone, Serialize, Deserialize)]
10	pub struct Pack {
11	    pub name: String,
12	    pub author: Option<String>,
13	    pub categories: Vec<Category>,
14	}
15	
16	/// A named grouping of macros.
17	#[derive(Debug, Clone, Serialize, Deserialize)]
18	pub struct Category {
19	    pub name: String,
20	    pub macros: Vec<MacroConfig>,
21	}
22	
23	impl Pack {
24	    /// Flatten the categories into a single list of macros.
25	    pub fn flatten(&self) -> Vec<MacroConfig> {
26	        self.categories
27	            .iter()
28	            .flat_map(|c| c.macros.clone())
29	            .collect()
30	    }
31	
32	    /// Load a pack from a directory containing `pack.yaml`.
33	    pub fn load_from_dir(dir: &Path) -> Result<Self> {
34	        let yaml_path = dir.join("pack.yaml");
35	        let file = std::fs::File::open(&yaml_path)
36	            .with_context(|| format!("Failed to open pack.yaml at {}", yaml_path.display()))?;
37	        let pack: Pack = serde_yaml_ng::from_reader(file)
38	            .with_context(|| format!("Failed to parse pack.yaml at {}", yaml_path.display()))?;
39	        Ok(pack)
40	    }
41	
42	    /// Save the pack to a directory as `pack.yaml`.
43	    pub fn save_to_dir(&self, dir: &Path) -> Result<()> {
44	        let yaml_path = dir.join("pack.yaml");
45	        let file = std::fs::File::create(&yaml_path)
46	            .with_context(|| format!("Failed to create pack.yaml at {}", yaml_path.display()))?;
47	        serde_yaml_ng::to_writer(file, self)
48	            .with_context(|| format!("Failed to serialize pack.yaml to {}", yaml_path.display()))?;
49	        Ok(())
50	    }
51	
52	    /// Import a .hdpack (ZIP) file.
53	    pub fn import(zip_path: &Path) -> Result<Self> {
54	        let file = std::fs::File::open(zip_path)?;
55	        let mut archive = zip::ZipArchive::new(file)?;
56	        
57	        // Find pack.yaml to get the pack name
58	        let mut pack_yaml_content = String::new();
59	        {
60	            let mut file = archive.by_name("pack.yaml")
61	                .context("ZIP archive missing pack.yaml")?;
62	            use std::io::Read;
63	            file.read_to_string(&mut pack_yaml_content)?;
64	        }
65	        
66	        let pack: Pack = serde_yaml_ng::from_str(&pack_yaml_content)
67	            .context("Failed to parse pack.yaml from ZIP")?;
68	        
69	        let dest_dir = get_profiles_dir()?.join(&pack.name);
70	        if dest_dir.exists() {
71	            std::fs::remove_dir_all(&dest_dir)?;
72	        }
73	        std::fs::create_dir_all(&dest_dir)?;
74	
75	        // Extract all files with path traversal protection
76	        for i in 0..archive.len() {
77	            let mut file = archive.by_index(i)?;
78	            let outpath = match file.enclosed_name() {
79	                Some(path) => dest_dir.join(path),
80	                None => continue,
81	            };
82	
83	            if (*file.name()).ends_with('/') {
84	                std::fs::create_dir_all(&outpath)?;
85	            } else {
86	                if let Some(p) = outpath.parent() {
87	                    if !p.exists() {
88	                        std::fs::create_dir_all(&p)?;
89	                    }
90	                }
91	                let mut outfile = std::fs::File::create(&outpath)?;
92	                std::io::copy(&mut file, &mut outfile)?;
93	            }
94	        }
95	
96	        Ok(pack)
97	    }
