48	    /// Load the currently active pack, if any.
49	    pub fn get_active_pack(&self) -> Result<Option<Pack>> {
50	        if let Some(ref name) = self.active_profile {
51	            let dir = get_profiles_dir()?.join(name);
52	            if dir.exists() {
53	                return Ok(Some(Pack::load_from_dir(&dir)?));
54	            }
55	        }
56	        Ok(None)
57	    }
